"""sklearn.multiclass — One-vs-Rest and One-vs-One multiclass strategies."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, clone


class OneVsRestClassifier(BaseEstimator, ClassifierMixin):
    """One-vs-the-rest (OvR) multiclass strategy.

    Parameters
    ----------
    estimator : classifier
    """

    def __init__(self, estimator=None):
        self.estimator = estimator

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        self.classes_ = np.unique(y)
        self.estimators_ = []
        for c in self.classes_:
            est = clone(self.estimator)
            binary_y = (y == c).astype(int)
            est.fit(X, binary_y)
            self.estimators_.append(est)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        scores = np.column_stack([
            est.predict_proba(X)[:, 1] if hasattr(est, 'predict_proba')
            else est.predict(X).astype(float)
            for est in self.estimators_
        ])
        return self.classes_[np.argmax(scores, axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        probs = np.column_stack([
            est.predict_proba(X)[:, 1] if hasattr(est, 'predict_proba')
            else est.predict(X).astype(float)
            for est in self.estimators_
        ])
        sums = probs.sum(axis=1, keepdims=True)
        sums[sums == 0] = 1
        return probs / sums


class OneVsOneClassifier(BaseEstimator, ClassifierMixin):
    """One-vs-One multiclass strategy.

    Parameters
    ----------
    estimator : classifier
    """

    def __init__(self, estimator=None):
        self.estimator = estimator

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        self.classes_ = np.unique(y)
        self.estimators_ = []
        self.pairs_ = []
        for i, ci in enumerate(self.classes_):
            for j, cj in enumerate(self.classes_):
                if i >= j:
                    continue
                mask = (y == ci) | (y == cj)
                est = clone(self.estimator)
                est.fit(X[mask], y[mask])
                self.estimators_.append(est)
                self.pairs_.append((ci, cj))
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        n = X.shape[0]
        votes = np.zeros((n, len(self.classes_)))
        class_idx = {c: i for i, c in enumerate(self.classes_)}
        for est, (ci, cj) in zip(self.estimators_, self.pairs_):
            preds = est.predict(X)
            for k in range(n):
                votes[k, class_idx[preds[k]]] += 1
        return self.classes_[np.argmax(votes, axis=1)]
